import { Transaction, Contributor, MatchResult, ContributorFile, Church, LearnedAssociation, GroupedReportData } from '../types';
import { Logger, Metrics } from './monitoringService';

// --- Centralized Constants ---

export const PLACEHOLDER_CHURCH: Church = {
    id: 'unidentified',
    name: '---', 
    address: '',
    logoUrl: '',
    pastor: '',
};

const STOP_WORDS_RESUMO = ['TOTAL GERAL', 'SALDO ANTERIOR', 'SALDO DO DIA', 'ACUMULADO MENSUAL', 'SALDO ATUAL'];

// --- Intelligent Search Filtering ---

export const getPotentialAmounts = (term: string): number[] => {
    const potentials: number[] = [];
    const cleanTerm = term.replace(/[^\d.,-]/g, '');
    if (!cleanTerm) return [];

    if (/^-?\d{1,3}(\.\d{3})*,\d{2}$/.test(cleanTerm)) {
        const val = parseFloat(cleanTerm.replace(/\./g, '').replace(',', '.'));
        if (!isNaN(val)) potentials.push(val);
    }

    if (/^-?\d+(\.\d+)?$/.test(cleanTerm)) {
        const val = parseFloat(cleanTerm);
        if (!isNaN(val)) potentials.push(val);
    }

    const brGeneric = cleanTerm.replace(/\./g, '').replace(',', '.');
    const valBR = parseFloat(brGeneric);
    if (!isNaN(valBR)) potentials.push(valBR);

    return [...new Set(potentials)];
};

export const filterByUniversalQuery = (record: MatchResult, query: string): boolean => {
    if (!query) return true;
    const searchTerms = query.toLowerCase().trim().split(/\s+/).filter(t => t.length > 0);

    return searchTerms.every(term => {
        // Use light normalization for search to preserve numbers (like "Buritis 2")
        const normalizedTerm = normalizeString(term);
        let matchFound = false;

        const txDesc = normalizeString(record.transaction.description);
        const txClean = normalizeString(record.transaction.cleanedDescription || '');
        const contribName = record.contributor ? normalizeString(record.contributor.name) : '';
        const churchName = normalizeString(record.church?.name || '');

        if (
            txDesc.includes(normalizedTerm) || 
            txClean.includes(normalizedTerm) || 
            contribName.includes(normalizedTerm) ||
            churchName.includes(normalizedTerm)
        ) {
            matchFound = true;
        }

        if (!matchFound && /\d/.test(term)) {
            const potentials = getPotentialAmounts(term);
            const txAmount = Math.abs(record.transaction.amount);
            const contribAmount = record.contributorAmount ? Math.abs(record.contributorAmount) : (record.contributor?.amount ? Math.abs(record.contributor.amount) : 0);

            const isNumericMatch = potentials.some(val => 
                Math.abs(txAmount - val) < 0.01 || 
                (contribAmount > 0 && Math.abs(contribAmount - val) < 0.01)
            );

            if (isNumericMatch) matchFound = true;
        }

        return matchFound;
    });
};

export const filterTransactionByUniversalQuery = (transaction: Transaction, query: string): boolean => {
    const fakeRecord: MatchResult = {
        transaction,
        contributor: null,
        status: 'NÃO IDENTIFICADO',
        church: PLACEHOLDER_CHURCH
    };
    return filterByUniversalQuery(fakeRecord, query);
};

// --- Heuristics & Parsers ---

export const parseDate = (dateString: string, defaultYear?: number | null): Date | null => {
    if (!dateString || typeof dateString !== 'string') return null;
    const trimmed = dateString.trim().replace(/^['"]|['"]$/g, '');

    const parts = trimmed.match(/(\d+)/g);
    if (!parts || parts.length < 2) return null;

    let day, month, year;
    if (parts.length === 2) {
        day = parseInt(parts[0], 10);
        month = parseInt(parts[1], 10);
        year = defaultYear || new Date().getFullYear();
    } else {
        if (parts[0].length === 4) { [year, month, day] = parts.map(p => parseInt(p, 10)); }
        else { 
            [day, month, year] = parts.map(p => parseInt(p, 10)); 
            if (String(year).length === 2) year += (year < 50 ? 2000 : 1900); 
        }
    }

    const date = new Date(Date.UTC(year, month - 1, day));
    return (!isNaN(date.getTime())) ? date : null;
};

const isDateString = (s: string): boolean => {
    if (!s) return false;
    return parseDate(s) !== null;
};

const isAmountString = (s: string): boolean => {
    if (!s || typeof s !== 'string') return false;
    const clean = s.trim();
    if (!/\d/.test(clean)) return false;
    if (/^(19|20)\d{2}$/.test(clean)) return false;

    const val = parseAmountString(clean);
    return !isNaN(val) && isFinite(val) && Math.abs(val) > 0.001; 
};

const parseAmountString = (s: string): number => {
    if (s === undefined || s === null) return 0;
    if (typeof s === 'number') return s;

    let cleanS = s.toString().trim();
    const isNegative = cleanS.includes('-') || cleanS.includes('(') || /\b(D|Db|Dr|Débito)\b/i.test(cleanS);
    cleanS = cleanS.replace(/[R$BRL\s]/gi, '').replace(/[^\d.,]/g, '');
    if (!cleanS) return 0;

    const lastComma = cleanS.lastIndexOf(',');
    const lastDot = cleanS.lastIndexOf('.');
    let parsable: string;

    if (lastComma !== -1 && lastDot !== -1) {
        if (lastComma > lastDot) parsable = cleanS.replace(/\./g, '').replace(',', '.');
        else parsable = cleanS.replace(/,/g, '');
    } 
    else if (lastComma !== -1) parsable = cleanS.replace(',', '.');
    else if (lastDot !== -1) {
        const parts = cleanS.split('.');
        if (parts.length > 2 || (parts[parts.length - 1].length === 3 && cleanS.length > 4)) parsable = cleanS.replace(/\./g, '');
        else parsable = cleanS;
    } 
    else parsable = cleanS;

    const value = parseFloat(parsable);
    if (isNaN(value)) return 0;
    return isNegative ? -Math.abs(value) : Math.abs(value);
};

// --- Parser Inteligente ---

const intelligentParser = <T>(
    content: string,
    type: 'EXTRATO' | 'LISTA'
): T[] => {
    if (!content) return [];

    let delimiter = ',';
    if (content.includes('\t')) delimiter = '\t';
    else if (content.includes(';')) {
        const semiCount = (content.match(/;/g) || []).length;
        const commaCount = (content.match(/,/g) || []).length;
        if (semiCount > commaCount * 0.3) delimiter = ';';
    }

    const parseCSVLine = (line: string, delim: string) => {
        const result = [];
        let cur = '';
        let inQuotes = false;
        for (let i = 0; i < line.length; i++) {
            const char = line[i];
            if (char === '"') inQuotes = !inQuotes;
            else if (char === delim && !inQuotes) {
                result.push(cur.trim().replace(/^['"]|['"]$/g, ''));
                cur = '';
            } else cur += char;
        }
        result.push(cur.trim().replace(/^['"]|['"]$/g, ''));
        return result;
    };

    const rawLines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    const lines = rawLines.map(l => parseCSVLine(l, delimiter));
    if (lines.length < 1) return [];

    // Detecção de Cabeçalhos
    let hDate = -1, hAmount = -1, hText = -1;
    for (const row of lines.slice(0, 15)) {
        row.forEach((cell, idx) => {
            const up = cell.toUpperCase().trim();
            if (['DATA', 'DATA_PAGAMENTO', 'DATA_PAGTO', 'DT_MOV', 'DT', 'MOVIMENTO'].includes(up)) hDate = idx;
            if (['VALOR', 'VALOR_PAGO', 'VR_LANC', 'CONTRIBUIÇÃO', 'QUANTIA', 'VALOR_RECEBIDO', 'LANCAMENTO', 'VALOR_LIQUIDO'].includes(up)) hAmount = idx;
            if (['NOME', 'CONTRIBUINTE', 'MEMBRO', 'NOME_DO_MEMBRO', 'DESCRIÇÃO', 'HISTORICO', 'NOME COMPLETO'].includes(up)) hText = idx;
        });
    }

    const sample = lines.slice(0, 60);
    const numCols = Math.max(...sample.map(l => l.length));
    const colStats = Array.from({ length: numCols }, () => ({
        dates: 0,
        amounts: 0,
        sumAbsValue: 0,
        uniqueValues: new Set<string>(),
        totalChars: 0,
        numericChars: 0
    }));

    sample.forEach(row => {
        row.forEach((cell, i) => {
            if (!cell || i >= numCols) return;
            if (isDateString(cell)) colStats[i].dates++;
            if (isAmountString(cell)) {
                const val = Math.abs(parseAmountString(cell));
                colStats[i].amounts++;
                colStats[i].sumAbsValue += val;
            }
            colStats[i].uniqueValues.add(cell.toUpperCase());
            colStats[i].totalChars += cell.length;
            colStats[i].numericChars += (cell.match(/\d/g) || []).length;
        });
    });

    const dateIdx = hDate !== -1 ? hDate : colStats.findIndex((s) => s.dates > (sample.length * 0.05));

    let amountIdx = hAmount;
    if (amountIdx === -1) {
        // Nova heurística: Pontua colunas que parecem valores financeiros (decimais, valores mais altos)
        // Evita colunas de categoria ou nomes que contenham números baixos como "Buritis 2"
        const candidates = colStats
            .map((s, i) => {
                // Checa se os valores tem cara de dinheiro (vírgula/ponto seguido de 2 dígitos)
                const hasDecimals = Array.from(s.uniqueValues).some(v => /[.,]\d{2}$/.test(v));
                const avgValue = s.amounts > 0 ? s.sumAbsValue / s.amounts : 0;

                // Score prioriza: Quantidade de números -> Decimais -> Média de valor
                // Colunas como "ID" ou "Setor 2" costumam ter média muito baixa (< 5)
                let score = s.amounts;
                if (hasDecimals) score *= 2; 
                if (avgValue > 5) score *= 1.5;

                return { i, score, avg: avgValue };
            })
            .filter(c => c.i !== dateIdx && c.score > 0)
            .sort((a, b) => b.score - a.score || b.avg - a.avg); 

        if (candidates.length > 0) amountIdx = candidates[0].i;
    }

    let textIdx = hText;
    if (textIdx === -1) {
        const textCandidates = colStats
            .map((s, i) => {
                const numericRatio = s.totalChars > 0 ? s.numericChars / s.totalChars : 1;
                const penalty = (numericRatio > 0.7 || i === dateIdx || i === amountIdx) ? 0.0001 : 1.0;
                return { i, score: s.uniqueValues.size * (s.totalChars / (sample.length || 1)) * penalty };
            })
            .sort((a, b) => b.score - a.score);
        if (textCandidates.length > 0 && textCandidates[0].score > 0.01) textIdx = textCandidates[0].i;
    }

    const results: any[] = [];
    lines.forEach((row, lineIndex) => {
        const dateRaw = dateIdx !== -1 ? row[dateIdx] : null;
        const amountRaw = amountIdx !== -1 ? row[amountIdx] : null;
        const textRaw = textIdx !== -1 ? row[textIdx] : null;

        if (!dateRaw || !amountRaw || !isDateString(dateRaw) || !isAmountString(amountRaw)) return;

        const parsedAmount = parseAmountString(amountRaw);
        if (isNaN(parsedAmount)) return;

        if (type === 'EXTRATO') {
            results.push({
                date: dateRaw,
                amount: parsedAmount,
                originalAmount: amountRaw,
                description: textRaw || 'LANÇAMENTO SEM DESCRIÇÃO',
                lineIndex 
            });
        } else {
            const upperText = textRaw ? textRaw.toString().toUpperCase() : '';
            const isStopWord = STOP_WORDS_RESUMO.some(sw => upperText && upperText.includes(sw));
            const isHeader = ['NOME', 'CONTRIBUINTE', 'MEMBRO', 'VALOR', 'DATA', 'VALOR_PAGO'].includes(upperText);

            if (!isHeader || (parsedAmount !== 0 && !isStopWord)) {
                results.push({ 
                    name: textRaw || 'CONTRIBUINTE NÃO IDENTIFICADO', 
                    date: dateRaw, 
                    amount: parsedAmount, 
                    originalAmount: amountRaw,
                    lineIndex 
                });
            }
        }
    });

    return results;
};

export const parseBankStatement = (content: string, customIgnoreKeywords: string[] = []): Transaction[] => {
    const raw = intelligentParser<any>(content, 'EXTRATO');
    const ignoreRegex = createIgnoreKeywordsRegex(customIgnoreKeywords);
    return raw.map((t, i) => ({
        ...t,
        id: `tx-${t.lineIndex}-${i}-${Math.random().toString(36).substr(2, 4)}`,
        cleanedDescription: cleanText(t.description, ignoreRegex)
    }));
};

export const parseContributors = (content: string, customIgnoreKeywords: string[] = []): Contributor[] => {
    const raw = intelligentParser<any>(content, 'LISTA');
    const ignoreRegex = createIgnoreKeywordsRegex(customIgnoreKeywords);
    return raw.map((c, i) => ({
        ...c,
        id: `contrib-${c.lineIndex}-${i}-${Math.random().toString(36).substr(2, 4)}`,
        cleanedName: cleanText(c.name, ignoreRegex), 
        normalizedName: normalizeForMatching(c.name, customIgnoreKeywords)
    }));
};

// --- Helpers de Limpeza ---

/**
 * Remove códigos numéricos longos (3+ dígitos), CPFs e CNPJs.
 */
const removeCodes = (text: string): string => {
    if (!text) return '';
    const cpfRegex = /\d{3}\.\d{3}\.\d{3}-\d{2}|\*\*\*\.\d{3}\.\d{3}-\*\*|\d{2}\.\d{3}\.\d{3}\/\d{4}-\d{2}/g;
    const numericCodeRegex = /\b\d{3,}\b/g; 

    let cleaned = text.replace(cpfRegex, '').replace(numericCodeRegex, '').replace(/\s+/g, ' ').trim();
    return cleaned.length > 0 ? cleaned : text;
};

/**
 * Normalização leve: minúsculas, remove acentos, MANTÉM NÚMEROS.
 * Vital para identificar igrejas como "Buritis 2".
 */
export const normalizeString = (str: string, ignoreKeywords: string[] = []): string => {
    if (!str) return '';
    let normalized = str.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

    if (ignoreKeywords.length > 0) {
        const regex = createIgnoreKeywordsRegex(ignoreKeywords);
        if (regex) normalized = normalized.replace(regex, '');
    }

    return normalized.replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
};

/**
 * Normalização pesada: remove códigos numéricos.
 * Usada APENAS para comparação de similaridade entre nomes de pessoas.
 */
export const normalizeForMatching = (str: string, ignoreKeywords: string[] = []): string => {
    const normalized = normalizeString(str, ignoreKeywords);
    return removeCodes(normalized);
};

const createIgnoreKeywordsRegex = (keywords: string[]): RegExp | null => {
    if (!keywords || keywords.length === 0) return null;
    const allVariations = keywords.flatMap(k => {
        const trimmed = k.trim();
        if (!trimmed) return [];
        const unaccented = trimmed.normalize("NFD").replace(/[\u0300-\u036f]/g, "");
        return unaccented !== trimmed ? [trimmed, unaccented] : [trimmed];
    });
    const pattern = allVariations.map(k => k.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|');
    return new RegExp(`(?:^|\\s|[-:/])(${pattern})(?:$|\\s|[-:/])`, 'gi');
};

const cleanText = (text: string, ignoreRegex: RegExp | null): string => {
    if (!text) return '';
    let cleaned = removeCodes(text);
    if (ignoreRegex) {
        let lastCleaned = '';
        while (cleaned !== lastCleaned) {
            lastCleaned = cleaned;
            cleaned = cleaned.replace(ignoreRegex, (match, p1) => match.replace(p1, ''));
        }
    }
    return cleaned.replace(/\s+/g, ' ').trim();
};

// --- Matching Logic ---

export const calculateNameSimilarity = (desc: string, contrib: Contributor): number => {
    const s1 = normalizeForMatching(desc);
    const s2 = contrib.normalizedName || normalizeForMatching(contrib.name);

    if (!s1 || !s2) return 0;

    // Ajuste CRÍTICO: Permitir que palavras com 1 caractere sejam comparadas SE forem dígitos.
    // Isso garante que "Buritis 2" não seja considerado igual a "Buritis 1".
    const words1 = new Set(s1.split(' ').filter(w => w.length > 1 || /\d/.test(w)));
    const words2 = new Set(s2.split(' ').filter(w => w.length > 1 || /\d/.test(w)));

    const intersect = new Set([...words1].filter(w => words2.has(w)));
    if (words1.size + words2.size === 0) return 0;
    return (2 * intersect.size) / (words1.size + words2.size) * 100;
};

export const matchTransactions = (
    transactions: Transaction[],
    contributorFiles: ContributorFile[],
    options: { similarityThreshold: number; dayTolerance: number; },
    learnedAssociations: LearnedAssociation[],
    churches: Church[],
    customIgnoreKeywords: string[] = []
): MatchResult[] => {
    const allContributors = contributorFiles.flatMap(file => 
        file.contributors.map(c => ({ ...c, church: file.church }))
    );

    const finalResults: MatchResult[] = [];
    const usedContributorIds = new Set<string>(); 

    transactions.forEach(tx => {
        let bestMatch: any = null;
        let highestScore = 0;

        // Use normalizeString for Learned Associations to preserve numbers like "Buritis 2"
        const txDescForLearning = normalizeString(tx.description, customIgnoreKeywords);

        const learned = learnedAssociations.find(la => la.normalizedDescription === txDescForLearning);
        if (learned) {
            const matchedContrib = allContributors.find(c => 
                !usedContributorIds.has(`${c.church.id}-${c.id}`) &&
                (c.normalizedName === learned.contributorNormalizedName) && 
                (c.church.id === learned.churchId)
            );
            if (matchedContrib) {
                usedContributorIds.add(`${matchedContrib.church.id}-${matchedContrib.id}`);
                finalResults.push({ transaction: tx, contributor: matchedContrib, status: 'IDENTIFICADO', church: matchedContrib.church, similarity: 100, matchMethod: 'LEARNED', contributorAmount: matchedContrib.amount });
                return;
            }
        }

        allContributors.forEach(contrib => {
            const uniqueId = `${contrib.church.id}-${contrib.id}`;
            if (usedContributorIds.has(uniqueId)) return;
            if (contrib.date && tx.date) {
                const d1 = parseDate(tx.date), d2 = parseDate(contrib.date);
                if (d1 && d2) {
                    const diffDays = Math.ceil(Math.abs(d2.getTime() - d1.getTime()) / (1000 * 3600 * 24));
                    if (diffDays > options.dayTolerance) return;
                }
            }
            const score = calculateNameSimilarity(tx.description, contrib);
            if (score >= options.similarityThreshold && score > highestScore) {
                highestScore = score;
                bestMatch = contrib;
            }
        });

        if (bestMatch) {
            usedContributorIds.add(`${bestMatch.church.id}-${bestMatch.id}`);
            finalResults.push({ transaction: tx, contributor: bestMatch, status: 'IDENTIFICADO', church: bestMatch.church, similarity: highestScore, matchMethod: 'AUTOMATIC', contributorAmount: bestMatch.amount });
        } else {
            // Robust Church Fallback: Assign to Church if the Church Name (with numbers) appears in the description
            const txDescNormalized = normalizeString(tx.description);
            const churchByDescription = churches.find(c => {
                if (c.id === 'unidentified' || !c.name || c.name === '---') return false;
                const normalizedChurchName = normalizeString(c.name);
                return normalizedChurchName.length > 2 && txDescNormalized.includes(normalizedChurchName);
            });

            if (churchByDescription) {
                finalResults.push({ 
                    transaction: tx, 
                    contributor: null, 
                    status: 'NÃO IDENTIFICADO', 
                    church: churchByDescription 
                });
            } else {
                finalResults.push({ transaction: tx, contributor: null, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH });
            }
        }
    });

    allContributors.forEach(contrib => {
        const uniqueId = `${contrib.church.id}-${contrib.id}`;
        if (!usedContributorIds.has(uniqueId)) {
            const virtualTx: Transaction = {
                id: `pending-${contrib.id}-${Math.random().toString(36).substr(2, 5)}`,
                date: contrib.date || '---',
                description: `[Pendente no Extrato] ${contrib.name}`,
                cleanedDescription: contrib.cleanedName || contrib.name,
                amount: 0, originalAmount: '0,00'
            };
            finalResults.push({ transaction: virtualTx, contributor: contrib, status: 'NÃO IDENTIFICADO', church: contrib.church, contributorAmount: contrib.amount, similarity: 0 });
        }
    });

    return finalResults;
};

export const groupResultsByChurch = (results: MatchResult[]): GroupedReportData => {
    const grouped: GroupedReportData = {};
    results.forEach(r => {
        const key = r.church?.id || 'unidentified';
        if (!grouped[key]) grouped[key] = [];
        grouped[key].push(r);
    });
    return grouped;
};

export const processExpenses = (txs: Transaction[]): MatchResult[] => 
    txs.map(t => ({ transaction: t, contributor: null, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH }));

export const cleanTransactionDescriptionForDisplay = (text: string): string => {
    if (!text) return '';
    let cleaned = removeCodes(text);
    cleaned = cleaned.replace(/<[^>]*>/g, '');
    const prefixes = ['PIX Recebido', 'TED', 'DOC', 'PIX', 'Pagamento'];
    const prefixRegex = new RegExp(`\\b(${prefixes.join('|')})\\b`, 'gi');
    cleaned = cleaned.replace(prefixRegex, '');
    return cleaned.replace(/\s+/g, ' ').trim();
};

import { Transaction, Contributor, MatchResult, ContributorFile, Church, LearnedAssociation, GroupedReportData } from '../types';
import { Logger, Metrics } from './monitoringService';

// --- Centralized Constants ---

export const PLACEHOLDER_CHURCH: Church = {
    id: 'unidentified',
    name: '---', 
    address: '',
    logoUrl: '',
    pastor: '',
};

const STOP_WORDS_RESUMO = ['TOTAL GERAL', 'SALDO ANTERIOR', 'SALDO DO DIA', 'ACUMULADO MENSUAL', 'SALDO ATUAL'];

// --- Intelligent Search Filtering ---

export const getPotentialAmounts = (term: string): number[] => {
    const potentials: number[] = [];
    const cleanTerm = term.replace(/[^\d.,-]/g, '');
    if (!cleanTerm) return [];

    if (/^-?\d{1,3}(\.\d{3})*,\d{2}$/.test(cleanTerm)) {
        const val = parseFloat(cleanTerm.replace(/\./g, '').replace(',', '.'));
        if (!isNaN(val)) potentials.push(val);
    }

    if (/^-?\d+(\.\d+)?$/.test(cleanTerm)) {
        const val = parseFloat(cleanTerm);
        if (!isNaN(val)) potentials.push(val);
    }

    const brGeneric = cleanTerm.replace(/\./g, '').replace(',', '.');
    const valBR = parseFloat(brGeneric);
    if (!isNaN(valBR)) potentials.push(valBR);

    return [...new Set(potentials)];
};

export const filterByUniversalQuery = (record: MatchResult, query: string): boolean => {
    if (!query) return true;
    const searchTerms = query.toLowerCase().trim().split(/\s+/).filter(t => t.length > 0);

    return searchTerms.every(term => {
        const normalizedTerm = normalizeString(term);
        let matchFound = false;

        const txDesc = normalizeString(record.transaction.description);
        const txClean = normalizeString(record.transaction.cleanedDescription || '');
        const contribName = record.contributor ? normalizeString(record.contributor.name) : '';
        const churchName = normalizeString(record.church?.name || '');

        if (
            txDesc.includes(normalizedTerm) || 
            txClean.includes(normalizedTerm) || 
            contribName.includes(normalizedTerm) ||
            churchName.includes(normalizedTerm)
        ) {
            matchFound = true;
        }

        if (!matchFound && /\d/.test(term)) {
            const potentials = getPotentialAmounts(term);
            const txAmount = Math.abs(record.transaction.amount);
            const contribAmount = record.contributorAmount ? Math.abs(record.contributorAmount) : (record.contributor?.amount ? Math.abs(record.contributor.amount) : 0);

            const isNumericMatch = potentials.some(val => 
                Math.abs(txAmount - val) < 0.01 || 
                (contribAmount > 0 && Math.abs(contribAmount - val) < 0.01)
            );

            if (isNumericMatch) matchFound = true;
        }

        return matchFound;
    });
};

export const filterTransactionByUniversalQuery = (transaction: Transaction, query: string): boolean => {
    const fakeRecord: MatchResult = {
        transaction,
        contributor: null,
        status: 'NÃO IDENTIFICADO',
        church: PLACEHOLDER_CHURCH
    };
    return filterByUniversalQuery(fakeRecord, query);
};

// --- Heuristics & Parsers ---

export const parseDate = (dateString: string, defaultYear?: number | null): Date | null => {
    if (!dateString || typeof dateString !== 'string') return null;
    const trimmed = dateString.trim().replace(/^['"]|['"]$/g, '');

    const parts = trimmed.match(/(\d+)/g);
    if (!parts || parts.length < 2) return null;

    let day, month, year;
    if (parts.length === 2) {
        day = parseInt(parts[0], 10);
        month = parseInt(parts[1], 10);
        year = defaultYear || new Date().getFullYear();
    } else {
        if (parts[0].length === 4) { [year, month, day] = parts.map(p => parseInt(p, 10)); }
        else { 
            [day, month, year] = parts.map(p => parseInt(p, 10)); 
            if (String(year).length === 2) year += (year < 50 ? 2000 : 1900); 
        }
    }

    const date = new Date(Date.UTC(year, month - 1, day));
    return (!isNaN(date.getTime())) ? date : null;
};

const isDateString = (s: string): boolean => {
    if (!s) return false;
    return parseDate(s) !== null;
};

const isAmountString = (s: string): boolean => {
    if (!s || typeof s !== 'string') return false;
    const clean = s.trim();
    if (!/\d/.test(clean)) return false;
    if (/^(19|20)\d{2}$/.test(clean)) return false;

    const val = parseAmountString(clean);
    return !isNaN(val) && isFinite(val) && Math.abs(val) > 0.001; 
};

const parseAmountString = (s: string): number => {
    if (s === undefined || s === null) return 0;
    if (typeof s === 'number') return s;

    let cleanS = s.toString().trim();
    const isNegative = cleanS.includes('-') || cleanS.includes('(') || /\b(D|Db|Dr|Débito)\b/i.test(cleanS);
    cleanS = cleanS.replace(/[R$BRL\s]/gi, '').replace(/[^\d.,]/g, '');
    if (!cleanS) return 0;

    const lastComma = cleanS.lastIndexOf(',');
    const lastDot = cleanS.lastIndexOf('.');
    let parsable: string;

    if (lastComma !== -1 && lastDot !== -1) {
        if (lastComma > lastDot) parsable = cleanS.replace(/\./g, '').replace(',', '.');
        else parsable = cleanS.replace(/,/g, '');
    } 
    else if (lastComma !== -1) parsable = cleanS.replace(',', '.');
    else if (lastDot !== -1) {
        const parts = cleanS.split('.');
        if (parts.length > 2 || (parts[parts.length - 1].length === 3 && cleanS.length > 4)) parsable = cleanS.replace(/\./g, '');
        else parsable = cleanS;
    } 
    else parsable = cleanS;

    const value = parseFloat(parsable);
    if (isNaN(value)) return 0;
    return isNegative ? -Math.abs(value) : Math.abs(value);
};

const intelligentParser = <T>(
    content: string,
    type: 'EXTRATO' | 'LISTA'
): T[] => {
    if (!content) return [];

    let delimiter = ',';
    if (content.includes('\t')) delimiter = '\t';
    else if (content.includes(';')) {
        const semiCount = (content.match(/;/g) || []).length;
        const commaCount = (content.match(/,/g) || []).length;
        if (semiCount > commaCount * 0.3) delimiter = ';';
    }

    const parseCSVLine = (line: string, delim: string) => {
        const result = [];
        let cur = '';
        let inQuotes = false;
        for (let i = 0; i < line.length; i++) {
            const char = line[i];
            if (char === '"') inQuotes = !inQuotes;
            else if (char === delim && !inQuotes) {
                result.push(cur.trim().replace(/^['"]|['"]$/g, ''));
                cur = '';
            } else cur += char;
        }
        result.push(cur.trim().replace(/^['"]|['"]$/g, ''));
        return result;
    };

    const rawLines = content.split(/\r?\n/).filter(l => l.trim().length > 0);
    const lines = rawLines.map(l => parseCSVLine(l, delimiter));
    if (lines.length < 1) return [];

    let hDate = -1, hAmount = -1, hText = -1;
    for (const row of lines.slice(0, 15)) {
        row.forEach((cell, idx) => {
            const up = cell.toUpperCase().trim();
            if (['DATA', 'DATA_PAGAMENTO', 'DATA_PAGTO', 'DT_MOV', 'DT', 'MOVIMENTO'].includes(up)) hDate = idx;
            if (['VALOR', 'VALOR_PAGO', 'VR_LANC', 'CONTRIBUIÇÃO', 'QUANTIA', 'VALOR_RECEBIDO', 'LANCAMENTO', 'VALOR_LIQUIDO'].includes(up)) hAmount = idx;
            if (['NOME', 'CONTRIBUINTE', 'MEMBRO', 'NOME_DO_MEMBRO', 'DESCRIÇÃO', 'HISTORICO', 'NOME COMPLETO'].includes(up)) hText = idx;
        });
    }

    const sample = lines.slice(0, 100);
    const numCols = Math.max(...sample.map(l => l.length));
    const colStats = Array.from({ length: numCols }, () => ({
        dates: 0,
        amounts: 0,
        sumAbsValue: 0,
        uniqueValues: new Set<string>(),
        decimalValues: 0,
        varianceCounter: new Map<number, number>()
    }));

    sample.forEach(row => {
        row.forEach((cell, i) => {
            if (!cell || i >= numCols) return;
            if (isDateString(cell)) colStats[i].dates++;
            if (isAmountString(cell)) {
                const val = Math.abs(parseAmountString(cell));
                colStats[i].amounts++;
                colStats[i].sumAbsValue += val;
                if (/[.,]\d{2}$/.test(cell.trim())) colStats[i].decimalValues++;
                colStats[i].varianceCounter.set(val, (colStats[i].varianceCounter.get(val) || 0) + 1);
            }
            colStats[i].uniqueValues.add(cell.toUpperCase());
        });
    });

    const dateIdx = hDate !== -1 ? hDate : colStats.findIndex((s) => s.dates > (sample.length * 0.05));

    let amountIdx = hAmount;
    if (amountIdx === -1) {
        const candidates = colStats
            .map((s, i) => {
                const avgValue = s.amounts > 0 ? s.sumAbsValue / s.amounts : 0;
                const uniqueRatio = s.amounts > 0 ? s.varianceCounter.size / s.amounts : 0;
                const decimalRatio = s.amounts > 0 ? s.decimalValues / s.amounts : 0;

                let score = s.amounts;
                if (decimalRatio > 0.5) score *= 3; 
                if (avgValue > 10) score *= 2;
                if (uniqueRatio < 0.2 && avgValue < 100) score *= 0.1; // Penalize ID-like columns (high repeat, low value)

                return { i, score, avg: avgValue };
            })
            .filter(c => c.i !== dateIdx && c.score > 0)
            .sort((a, b) => b.score - a.score || b.avg - a.avg); 

        if (candidates.length > 0) amountIdx = candidates[0].i;
    }

    let textIdx = hText;
    if (textIdx === -1) {
        const textCandidates = colStats
            .map((s, i) => ({ i, score: s.uniqueValues.size * (i !== dateIdx && i !== amountIdx ? 1 : 0.001) }))
            .sort((a, b) => b.score - a.score);
        if (textCandidates.length > 0 && textCandidates[0].score > 0) textIdx = textCandidates[0].i;
    }

    const results: any[] = [];
    lines.forEach((row, lineIndex) => {
        const dateRaw = dateIdx !== -1 ? row[dateIdx] : null;
        const amountRaw = amountIdx !== -1 ? row[amountIdx] : null;
        const textRaw = textIdx !== -1 ? row[textIdx] : null;

        if (!dateRaw || !amountRaw || !isDateString(dateRaw) || !isAmountString(amountRaw)) return;

        const parsedAmount = parseAmountString(amountRaw);
        if (isNaN(parsedAmount)) return;

        if (type === 'EXTRATO') {
            results.push({
                date: dateRaw,
                amount: parsedAmount,
                originalAmount: amountRaw,
                description: textRaw || 'LANÇAMENTO SEM DESCRIÇÃO',
                lineIndex 
            });
        } else {
            const upperText = textRaw ? textRaw.toString().toUpperCase() : '';
            const isStopWord = STOP_WORDS_RESUMO.some(sw => upperText && upperText.includes(sw));
            const isHeader = ['NOME', 'CONTRIBUINTE', 'MEMBRO', 'VALOR', 'DATA'].includes(upperText);

            if (!isHeader || (parsedAmount !== 0 && !isStopWord)) {
                results.push({ 
                    name: textRaw || 'CONTRIBUINTE NÃO IDENTIFICADO', 
                    date: dateRaw, 
                    amount: parsedAmount, 
                    originalAmount: amountRaw,
                    lineIndex 
                });
            }
        }
    });

    return results;
};

export const parseBankStatement = (content: string, customIgnoreKeywords: string[] = []): Transaction[] => {
    const raw = intelligentParser<any>(content, 'EXTRATO');
    return raw.map((t, i) => ({
        ...t,
        id: `tx-${t.lineIndex}-${i}-${Math.random().toString(36).substr(2, 4)}`,
        cleanedDescription: cleanText(t.description, createIgnoreKeywordsRegex(customIgnoreKeywords))
    }));
};

export const parseContributors = (content: string, customIgnoreKeywords: string[] = []): Contributor[] => {
    const raw = intelligentParser<any>(content, 'LISTA');
    const ignoreRegex = createIgnoreKeywordsRegex(customIgnoreKeywords);
    return raw.map((c, i) => ({
        ...c,
        id: `contrib-${c.lineIndex}-${i}-${Math.random().toString(36).substr(2, 4)}`,
        cleanedName: cleanText(c.name, ignoreRegex), 
        normalizedName: normalizeForMatching(c.name, customIgnoreKeywords)
    }));
};

const removeCodes = (text: string): string => {
    if (!text) return '';
    const cpfRegex = /\d{3}\.\d{3}\.\d{3}-\d{2}|\*\*\*\.\d{3}\.\d{3}-\*\*|\d{2}\.\d{3}\.\d{3}\/\d{4}-\d{2}/g;
    const numericCodeRegex = /\b\d{4,}\b/g; // Changed to 4+ to protect names like "Buritis 2" or "Sede 101"

    return text.replace(cpfRegex, '').replace(numericCodeRegex, '').replace(/\s+/g, ' ').trim();
};

export const normalizeString = (str: string, ignoreKeywords: string[] = []): string => {
    if (!str) return '';
    let normalized = str.toLowerCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");

    if (ignoreKeywords.length > 0) {
        const regex = createIgnoreKeywordsRegex(ignoreKeywords);
        if (regex) normalized = normalized.replace(regex, ' ');
    }

    return normalized.replace(/[^a-z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
};

export const normalizeForMatching = (str: string, ignoreKeywords: string[] = []): string => {
    return removeCodes(normalizeString(str, ignoreKeywords));
};

const createIgnoreKeywordsRegex = (keywords: string[]): RegExp | null => {
    if (!keywords || keywords.length === 0) return null;
    const pattern = keywords.map(k => k.trim().replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).filter(Boolean).join('|');
    return pattern ? new RegExp(`\\b(${pattern})\\b`, 'gi') : null;
};

const cleanText = (text: string, ignoreRegex: RegExp | null): string => {
    if (!text) return '';
    let cleaned = removeCodes(text);
    if (ignoreRegex) cleaned = cleaned.replace(ignoreRegex, '');
    return cleaned.replace(/\s+/g, ' ').trim();
};

export const calculateNameSimilarity = (desc: string, contrib: Contributor): number => {
    const s1 = normalizeForMatching(desc);
    const s2 = contrib.normalizedName || normalizeForMatching(contrib.name);
    if (!s1 || !s2) return 0;

    const words1 = new Set(s1.split(' ').filter(w => w.length > 1 || /\d/.test(w)));
    const words2 = new Set(s2.split(' ').filter(w => w.length > 1 || /\d/.test(w)));

    const intersect = new Set([...words1].filter(w => words2.has(w)));
    if (words1.size + words2.size === 0) return 0;
    return (2 * intersect.size) / (words1.size + words2.size) * 100;
};

export const matchTransactions = (
    transactions: Transaction[],
    contributorFiles: ContributorFile[],
    options: { similarityThreshold: number; dayTolerance: number; },
    learnedAssociations: LearnedAssociation[],
    churches: Church[],
    customIgnoreKeywords: string[] = []
): MatchResult[] => {
    const finalResults: MatchResult[] = [];
    const usedContributorIds = new Set<string>();

    transactions.forEach(tx => {
        let bestMatch: any = null;
        let highestScore = 0;

        const txDescNormalized = normalizeString(tx.description, customIgnoreKeywords);

        const learned = learnedAssociations.find(la => la.normalizedDescription === txDescNormalized);
        if (learned) {
            const file = contributorFiles.find(f => f.church.id === learned.churchId);
            if (file) {
                const matchedContrib = file.contributors.find(c => 
                    !usedContributorIds.has(`${file.church.id}-${c.id}`) &&
                    (c.normalizedName === learned.contributorNormalizedName)
                );
                if (matchedContrib) {
                    usedContributorIds.add(`${file.church.id}-${matchedContrib.id}`);
                    finalResults.push({ transaction: tx, contributor: matchedContrib, status: 'IDENTIFICADO', church: file.church, similarity: 100, matchMethod: 'LEARNED', contributorAmount: matchedContrib.amount });
                    return;
                }
            }
        }

        contributorFiles.forEach(file => {
            file.contributors.forEach(contrib => {
                const uniqueId = `${file.church.id}-${contrib.id}`;
                if (usedContributorIds.has(uniqueId)) return;

                if (contrib.date && tx.date) {
                    const d1 = parseDate(tx.date), d2 = parseDate(contrib.date);
                    if (d1 && d2) {
                        const diffDays = Math.ceil(Math.abs(d2.getTime() - d1.getTime()) / (1000 * 3600 * 24));
                        if (diffDays > options.dayTolerance) return;
                    }
                }
                const score = calculateNameSimilarity(tx.description, contrib);
                if (score >= options.similarityThreshold && score > highestScore) {
                    highestScore = score;
                    bestMatch = { contrib, church: file.church };
                }
            });
        });

        if (bestMatch) {
            usedContributorIds.add(`${bestMatch.church.id}-${bestMatch.contrib.id}`);
            finalResults.push({ transaction: tx, contributor: bestMatch.contrib, status: 'IDENTIFICADO', church: bestMatch.church, similarity: highestScore, matchMethod: 'AUTOMATIC', contributorAmount: bestMatch.contrib.amount });
        } else {
            const churchByDesc = churches.find(c => c.name !== '---' && txDescNormalized.includes(normalizeString(c.name)));
            finalResults.push({ transaction: tx, contributor: null, status: 'NÃO IDENTIFICADO', church: churchByDesc || PLACEHOLDER_CHURCH });
        }
    });

    contributorFiles.forEach(file => {
        file.contributors.forEach(contrib => {
            const uniqueId = `${file.church.id}-${contrib.id}`;
            if (!usedContributorIds.has(uniqueId)) {
                finalResults.push({ 
                    transaction: { id: `pending-${contrib.id}`, date: contrib.date || '---', description: `[Pendente] ${contrib.name}`, amount: 0 },
                    contributor: contrib, status: 'NÃO IDENTIFICADO', church: file.church, contributorAmount: contrib.amount, similarity: 0 
                });
            }
        });
    });

    return finalResults;
};

export const groupResultsByChurch = (results: MatchResult[]): GroupedReportData => {
    const grouped: GroupedReportData = {};
    results.forEach(r => {
        const key = r.church?.id || 'unidentified';
        if (!grouped[key]) grouped[key] = [];
        grouped[key].push(r);
    });
    return grouped;
};

export const processExpenses = (txs: Transaction[]): MatchResult[] => 
    txs.map(t => ({ transaction: t, contributor: null, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH }));

export const cleanTransactionDescriptionForDisplay = (text: string): string => {
    if (!text) return '';
    let cleaned = removeCodes(text);
    const prefixes = ['PIX Recebido', 'TED', 'DOC', 'PIX', 'Pagamento'];
    const prefixRegex = new RegExp(`\\b(${prefixes.join('|')})\\b`, 'gi');
    cleaned = cleaned.replace(prefixRegex, '');
    return cleaned.replace(/\s+/g, ' ').trim();
};
